<script>

function wrapLabelText(labelStr) {

    if (labelStr.length <= 16) return labelStr;

    const words = labelStr.split(' ');

    const lines = [];

    let currentLine = '';

    for (let i = 0; i < words.length; i++) {

        const word = words[i];

        if ((currentLine + word).length > 16) {

            if (currentLine) lines.push(currentLine.trim());

            currentLine = word + ' ';

        } else {

            currentLine += word + ' ';

        }

    }

    if (currentLine) lines.push(currentLine.trim());

    return lines;

}



